Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** from `Microsoft.AspNetCore.Mvc.Testing`. It hosts your app in-memory with a test `HttpClient` — no real port, no real server.

Here's the pattern:

```csharp
// 1. Add these packages to your test project:
//    Microsoft.AspNetCore.Mvc.Testing
//    xunit (or your preferred test framework)

// 2. Create a factory (customize config if needed):
public class McpServerFactory : WebApplicationFactory<Program>
{
    protected override void ConfigureWebHost(IWebHostBuilder builder)
    {
        builder.ConfigureServices(services =>
        {
            // Swap real dependencies for test doubles here
        });
    }
}

// 3. Write tests against the MCP HTTP+SSE endpoints:
public class McpIntegrationTests : IClassFixture<McpServerFactory>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(McpServerFactory factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        // POST a JSON-RPC "initialize" request to the MCP endpoint
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/list",
            @params = new { }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 3,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.False(body.GetProperty("result")
                        .GetProperty("isError")
                        .GetBoolean());
    }
}
```

**Key points:**

- **No real port** — `WebApplicationFactory` uses an in-memory `TestServer`; everything stays in-process.
- **SSE endpoint** — If your server uses the SSE transport (`/sse`), you can read the stream via `GetStreamAsync` and parse `text/event-stream` lines manually.
- **Swap dependencies** — Use `ConfigureWebHost` to replace databases, external services, etc. with fakes.
- **Adjust the URL path** (`/mcp`, `/sse`, `/message`) to match your server's actual route configuration.

If you're using the **Streamable HTTP** transport (single `POST` endpoint), the pattern above works directly. For the **SSE transport** (separate `/sse` + `/message` endpoints), open `/sse` with `GetStreamAsync` to receive the session endpoint, then `POST` JSON-RPC messages to it.
